query:
-- Fix using LIKE to handle both straight and curly apostrophes
UPDATE book_profiles SET authorName = 'Rhea Orion' 
WHERE bookTitle LIKE 'A Therapist%Guide to Consensual Nonmonogamy' AND (authorName IS NULL OR authorName = '');

UPDATE book_profiles SET authorName = 'Stephen Poland' 
WHERE bookTitle LIKE 'Founder%Pocket Guide' AND (authorName IS NULL OR authorName = '');

-- Reset the not-found cover for Immune so the rebuild will re-scrape it
UPDATE book_profiles SET coverImageUrl = NULL, s3CoverUrl = NULL, s3CoverKey = NULL 
WHERE bookTitle = 'Immune by Philip Dettmer';

-- Verify
SELECT bookTitle, authorName, coverImageUrl FROM book_profiles 
WHERE (authorName IS NULL OR authorName = '') OR coverImageUrl IN ('not-found','skipped') OR coverImageUrl IS NULL
ORDER BY bookTitle;

